"use client";

import { useState } from "react";
import { syncDrugs } from "@/util/drugApi";

export default function DrugPage() {
    const [keyword, setKeyword] = useState("");
    const [drugs, setDrugs] = useState<any[]>([]); // 약품 리스트
    const [loading, setLoading] = useState(false); // 로딩 상태
    const [message, setMessage] = useState(""); // 알림 메시지

    // 테마 컬러 설정
    const themeColor = '#4f46e5'; // Indigo



    // 🔄 전체 동기화 핸들러
    const handleSync = async () => {
        if (!confirm("모든 e약은요 데이터를 동기화하시겠습니까? (시간이 소요됩니다)")) return;

        setLoading(true);
        setMessage("데이터 동기화 중... 잠시만 기다려주세요.");
        try {
            const resultMsg = await syncDrugs();
            setMessage("✅ " + resultMsg);
        } catch (err) {
            setMessage("❌ 동기화 실패! 백엔드 로그를 확인해주세요.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px', maxWidth: '900px', margin: '0 auto', fontFamily: 'inherit' }}>
            <h1 style={{ fontSize: '28px', fontWeight: '800', marginBottom: '25px', color: '#1e293b' }}>
                💊 e약은요 데이터 관리
            </h1>

            {/* 상단 컨트롤 패널 (업로드하신 파일 스타일 적용) */}
            <div style={{ 
                padding: '25px', 
                border: '1px solid #e2e8f0', 
                borderRadius: '12px', 
                backgroundColor: '#f8fafc',
                marginBottom: '30px'
            }}>
                <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                    <form onSubmit={handleSearch} style={{ flex: 1, display: 'flex', gap: '8px', minWidth: '300px' }}>
                        <input
                            type="text"
                            placeholder="약 이름 검색 (예: 타이레놀)"
                            style={{
                                flex: 1,
                                padding: '12px 15px',
                                border: '1px solid #cbd5e1',
                                borderRadius: '8px',
                                fontSize: '15px',
                                outline: 'none'
                            }}
                            value={keyword}
                            onChange={(e) => setKeyword(e.target.value)}
                        />
                        <button
                            type="submit"
                            disabled={loading}
                            style={{
                                padding: '12px 24px',
                                backgroundColor: loading ? '#ccc' : themeColor,
                                color: '#fff',
                                border: 'none',
                                borderRadius: '8px',
                                cursor: loading ? 'not-allowed' : 'pointer',
                                fontWeight: 'bold'
                            }}
                        >
                            검색
                        </button>
                    </form>

                    <button
                        onClick={handleSync}
                        disabled={loading}
                        style={{
                            padding: '12px 24px',
                            backgroundColor: loading ? '#ccc' : '#10b981',
                            color: '#fff',
                            border: 'none',
                            borderRadius: '8px',
                            cursor: loading ? 'not-allowed' : 'pointer',
                            fontWeight: 'bold',
                            whiteSpace: 'nowrap'
                        }}
                    >
                        {loading ? "작업 중..." : "🔄 전체 데이터 동기화"}
                    </button>
                </div>

                {message && (
                    <div style={{ 
                        marginTop: '20px', 
                        padding: '15px', 
                        borderRadius: '8px',
                        fontSize: '14px',
                        backgroundColor: message.includes("❌") ? "#fff1f2" : "#f5f3ff",
                        color: message.includes("❌") ? "#e11d48" : themeColor,
                        border: `1px solid ${message.includes("❌") ? "#fda4af" : "#c7d2fe"}`,
                        textAlign: 'center'
                    }}>
                        {message}
                    </div>
                )}
            </div>

            {/* 결과 리스트 (카드 그리드 형태) */}
            <div style={{ 
                display: 'grid', 
                gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))', 
                gap: '20px' 
            }}>
                {drugs.map((drug) => (
                    <div key={drug.itemSeq} style={{ 
                        border: '1px solid #e2e8f0', 
                        borderRadius: '12px', 
                        padding: '20px', 
                        backgroundColor: '#fff',
                        display: 'flex',
                        flexDirection: 'column'
                    }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '10px' }}>
                            <h3 style={{ fontSize: '18px', fontWeight: '700', margin: 0, color: '#0f172a' }}>{drug.itemName}</h3>
                            <span style={{ fontSize: '11px', color: '#64748b', backgroundColor: '#f1f5f9', padding: '2px 6px', borderRadius: '4px' }}>
                                No. {drug.itemSeq}
                            </span>
                        </div>
                        
                        <p style={{ fontSize: '13px', color: '#64748b', marginBottom: '15px' }}>{drug.entpName}</p>
                        
                        {drug.itemImage && (
                            <img 
                                src={drug.itemImage} 
                                alt={drug.itemName} 
                                style={{ 
                                    width: '100%', 
                                    height: '180px', 
                                    objectFit: 'cover', // 🚀 이전 에러 수정 완료
                                    borderRadius: '8px', 
                                    marginBottom: '15px',
                                    border: '1px solid #f1f5f9'
                                }} 
                            />
                        )}

                        <div style={{ marginTop: 'auto' }}>
                            <div style={{ 
                                fontSize: '13px', 
                                color: '#334155', 
                                backgroundColor: '#f8fafc', 
                                padding: '12px', 
                                borderRadius: '8px',
                                lineHeight: '1.6'
                            }}>
                                <strong style={{ color: themeColor }}>효능:</strong> {drug.efficacy}
                            </div>
                        </div>
                    </div>
                ))}
            </div>
            
            {drugs.length === 0 && !loading && (
                <div style={{ textAlign: 'center', color: '#94a3b8', padding: '80px 0' }}>
                    데이터가 없습니다. 검색하거나 동기화를 진행해주세요.
                </div>
            )}
            
            <div style={{ marginTop: '40px', textAlign: 'center' }}>
                <a href="/admin" style={{ color: '#64748b', textDecoration: 'none', fontSize: '14px' }}>← 어드민 페이지로 돌아가기</a>
            </div>
        </div>
    );
}